head.b:skin:
:root {
  /* CYBERPUNK/GAMING COLOR PALETTE */
  --bg: #050508;
  --bg2: #0a0a12;
  --bg3: #12121c;
  --border: rgba(0, 255, 255, 0.2);
  --border2: rgba(255, 0, 255, 0.3);
  --accent: #00ffff; /* Neon Cyan */
  --accent2: #ff00ff; /* Neon Magenta */
  --accent3: #39ff14; /* Neon Green */
  --text: #e0e0e0;
  --text2: #8a8a9e;
  --card: rgba(10, 10, 15, 0.7);
  --glow: rgba(0, 255, 255, 0.4);
  --shadow-sm: 0 4px 15px rgba(0,0,0,0.6);
  --shadow-md: 0 0 15px rgba(0, 255, 255, 0.15);
  --shadow-glow: 0 0 20px rgba(0,255,255,0.6), 0 0 40px rgba(255,0,255,0.2);
  --font-heading: 'Orbitron', sans-serif;
  --font-body: 'Rajdhani', sans-serif;
}

[data-theme="light"] {
  --bg: #f0f0f5;
  --bg2: #e0e0e8;
  --bg3: #d0d0d8;
  --border: rgba(0, 150, 255, 0.4);
  --border2: rgba(200, 0, 200, 0.4);
  --accent: #0066ff;
  --accent2: #cc00cc;
  --accent3: #00aa00;
  --text: #111118;
  --text2: #444455;
  --card: rgba(255, 255, 255, 0.8);
  --glow: rgba(0, 102, 255, 0.3);
  --shadow-md: 0 10px 30px rgba(0,0,0,0.1);
  --shadow-glow: 0 5px 20px rgba(0,102,255,0.4);
}

* { margin:0; padding:0; box-sizing:border-box; }
html { scroll-behavior: smooth; }
body {
  font-family: var(--font-body);
  font-size: 1.1rem;
  background: var(--bg);
  color: var(--text);
  transition: background 0.4s, color 0.4s;
  overflow-x: hidden;
}

h1, h2, h3, h4, h5, h6, .nav-logo {
  font-family: var(--font-heading);
  text-transform: uppercase;
  letter-spacing: 1px;
}

/* ── PROGRESS BAR ── */
#reading-progress {
  position: fixed; top: 0; left: 0; height: 4px;
  background: linear-gradient(90deg, var(--accent2), var(--accent), var(--accent3));
  z-index: 99999; width: 0%; transition: width 0.1s linear;
  box-shadow: 0 0 10px var(--accent);
}

/* ── SUPER LIVE 3D GRID BACKGROUND ── */
.animated-bg {
  position: fixed; inset: 0; z-index: -2; pointer-events: none; overflow: hidden;
  background: radial-gradient(circle at center, var(--bg2) 0%, var(--bg) 100%);
}
.bg-grid {
  position: absolute;
  width: 200vw; height: 200vh;
  left: -50vw; top: 10vh;
  background-image: 
    linear-gradient(var(--border) 1px, transparent 1px),
    linear-gradient(90deg, var(--border) 1px, transparent 1px);
  background-size: 60px 60px;
  transform: perspective(800px) rotateX(60deg) translateY(0);
  animation: cyberGrid 10s linear infinite;
  mask-image: linear-gradient(to top, rgba(0,0,0,1) 0%, rgba(0,0,0,0) 80%);
  -webkit-mask-image: linear-gradient(to top, rgba(0,0,0,1) 0%, rgba(0,0,0,0) 80%);
}
@keyframes cyberGrid {
  0% { transform: perspective(800px) rotateX(60deg) translateY(0); }
  100% { transform: perspective(800px) rotateX(60deg) translateY(60px); }
}

/* CRT Scanlines */
.scanlines {
  position: fixed; inset: 0; pointer-events: none; z-index: 9998;
  background: linear-gradient(to bottom, rgba(255,255,255,0), rgba(255,255,255,0) 50%, rgba(0,0,0,0.1) 50%, rgba(0,0,0,0.1));
  background-size: 100% 4px;
  opacity: 0.5;
}

/* ── SCROLL REVEAL ANIMATIONS ── */
.reveal {
  opacity: 0;
  transform: translateY(40px) scale(0.98);
  transition: opacity 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.275), transform 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.275);
  will-change: opacity, transform;
}
.reveal.visible { opacity: 1; transform: translateY(0) scale(1); }
.delay-1 { transition-delay: 0.1s; }
.delay-2 { transition-delay: 0.2s; }
.delay-3 { transition-delay: 0.3s; }

/* ── INTRO ANIMATION ── */
#intro-overlay {
  position: fixed; inset: 0; z-index: 9999; background: #000;
  display: flex; align-items: center; justify-content: center; flex-direction: column; gap: 1rem;
  animation: overlayOut 0.5s ease 2s forwards;
}
.intro-name {
  font-size: clamp(2.5rem, 8vw, 5rem); font-family: var(--font-heading); font-weight: 900;
  background: linear-gradient(135deg, var(--accent), var(--accent2)); -webkit-background-clip: text; -webkit-text-fill-color: transparent;
  opacity: 0; transform: scale(0.8); animation: glitchIn 0.5s cubic-bezier(0.175, 0.885, 0.32, 1.275) 0.3s forwards;
}
.intro-sub {
  font-size: 1.2rem; color: var(--accent3); letter-spacing: 0.2em; text-transform: uppercase; font-weight: 600;
  opacity: 0; animation: fadeUp 0.5s ease 0.6s forwards;
}
@keyframes glitchIn { to { opacity: 1; transform: scale(1); text-shadow: 0 0 20px var(--accent); } }
@keyframes overlayOut { to { opacity: 0; pointer-events: none; } }
@keyframes fadeUp { to { opacity: 1; transform: translateY(0); } }

/* ── NAV ── */
nav { position: relative; z-index: 100; background: rgba(5,5,8,0.8); backdrop-filter: blur(10px); border-bottom: 1px solid var(--border); }
.nav-container { display: flex; align-items: center; justify-content: space-between; width: 100%; max-width: 1200px; padding: 1rem 2rem; margin: 0 auto; }
.nav-logo-section { display: flex; align-items: center; margin: 0; padding: 0; }
.nav-logo-section .widget { margin: 0; }
.nav-logo { font-size: 1.8rem; font-weight: 900; color: var(--accent); text-decoration: none; text-shadow: 0 0 10px var(--glow); transition: all 0.3s; }
.nav-logo:hover { color: var(--text); text-shadow: 0 0 15px var(--accent2); }

.nav-right { display: flex; align-items: center; gap: 2rem; }
.nav-links-wrapper .widget { margin: 0; }
.nav-links { display: flex; gap: 2rem; list-style: none; align-items: center; margin: 0; padding: 0; }
.nav-links a { font-family: var(--font-heading); color: var(--text); text-decoration: none; font-size: 0.95rem; font-weight: 700; text-transform: uppercase; transition: all 0.3s; letter-spacing: 1px; }
.nav-links a:hover { color: var(--accent); text-shadow: 0 0 8px var(--accent); }

/* ── DROPDOWN MENU ── */
.dropdown { position: relative; display: inline-block; }
.dropdown .dropbtn { cursor: pointer; display: flex; align-items: center; gap: 4px; }
.dropdown-content { display: none; position: absolute; background-color: var(--bg2); min-width: 200px; box-shadow: var(--shadow-md); border: 1px solid var(--border); border-top: 3px solid var(--accent); top: 100%; left: -1rem; z-index: 101; padding: 0.5rem 0; }
.dropdown-content a { color: var(--text); padding: 0.75rem 1.5rem; text-decoration: none; display: block; font-family: var(--font-body); font-size: 1.1rem; transition: all 0.2s; }
.dropdown-content a:hover { background-color: rgba(0,255,255,0.1); color: var(--accent); padding-left: 2rem; border-left: 3px solid var(--accent); }
.dropdown:hover .dropdown-content { display: block; animation: dropFade 0.2s ease forwards; }
@keyframes dropFade { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }

.hamburger { display: none; background: none; border: none; cursor: pointer; padding: 0.5rem; }
.hamburger svg { width: 32px; height: 32px; fill: var(--accent); filter: drop-shadow(0 0 5px var(--accent)); }

/* ── SEARCH BAR ── */
.search-form { display: flex; align-items: center; position: relative; }
.search-input { background: var(--bg3); border: 1px solid var(--border); color: var(--text); padding: 0.6rem 1rem 0.6rem 2.5rem; clip-path: polygon(10px 0, 100% 0, 100% calc(100% - 10px), calc(100% - 10px) 100%, 0 100%, 0 10px); font-family: var(--font-body); font-size: 1rem; font-weight: 600; width: 180px; transition: all 0.3s; }
.search-input::placeholder { color: var(--text2); }
.search-input:focus { outline: none; border-color: var(--accent); width: 220px; box-shadow: 0 0 15px var(--glow); }
.search-btn { position: absolute; left: 10px; background: none; border: none; padding: 0; display: flex; align-items: center; justify-content: center; cursor: pointer; }
.search-btn svg { width: 18px; height: 18px; fill: var(--text2); transition: fill 0.2s; }
.search-input:focus + .search-btn svg, .search-btn:hover svg { fill: var(--accent); filter: drop-shadow(0 0 3px var(--accent)); }

/* ── DARK MODE TOGGLE ── */
#theme-toggle { background: var(--bg3); border: 1px solid var(--border); clip-path: polygon(5px 0, 100% 0, 100% calc(100% - 5px), calc(100% - 5px) 100%, 0 100%, 0 5px); width: 56px; height: 30px; cursor: pointer; position: relative; transition: all 0.3s; flex-shrink: 0; }
#theme-toggle::before { content: ''; position: absolute; top: 3px; left: 3px; width: 22px; height: 22px; background: var(--accent); box-shadow: 0 0 10px var(--accent); transition: transform 0.3s; }
[data-theme="light"] #theme-toggle::before { transform: translateX(26px); background: var(--accent2); box-shadow: 0 0 10px var(--accent2); }

/* ── CRAZY GAMING BUTTONS ── */
.btn-primary, .btn-secondary {
  display: inline-flex; align-items: center; gap: 10px; padding: 1rem 2rem;
  font-family: var(--font-heading); font-weight: 700; font-size: 1rem; text-transform: uppercase; letter-spacing: 1px;
  text-decoration: none; border: none; cursor: pointer; position: relative;
  transition: all 0.3s cubic-bezier(0.25, 0.8, 0.25, 1);
  clip-path: polygon(15px 0, 100% 0, 100% calc(100% - 15px), calc(100% - 15px) 100%, 0 100%, 0 15px);
}
.btn-primary {
  background: rgba(0,255,255,0.1); color: var(--accent) !important;
  border: 1px solid var(--accent);
  box-shadow: inset 0 0 10px var(--glow), 0 0 15px var(--glow);
}
.btn-primary:hover {
  background: var(--accent); color: #000 !important;
  box-shadow: 0 0 30px var(--accent); transform: translateY(-3px) scale(1.02);
}
.btn-secondary {
  background: rgba(255,0,255,0.05); color: var(--accent2);
  border: 1px solid var(--accent2);
}
.btn-secondary:hover {
  background: var(--accent2); color: #000 !important;
  box-shadow: 0 0 30px var(--accent2); transform: translateY(-3px) scale(1.02);
}

/* ── HERO ── */
.hero { min-height: 80vh; padding: 4rem 2rem; position: relative; display: flex; flex-direction: column; align-items: center; justify-content: center; }
.hero-text-wrapper { width: 100%; max-width: 900px; text-align: center; position: relative; z-index: 10; }
.hero-tag { display: inline-flex; align-items: center; gap: 8px; background: rgba(57, 255, 20, 0.1); border: 1px solid var(--accent3); clip-path: polygon(10px 0, 100% 0, 100% calc(100% - 10px), calc(100% - 10px) 100%, 0 100%, 0 10px); padding: 8px 18px; font-size: 0.9rem; font-weight: 700; color: var(--accent3); letter-spacing: 2px; text-transform: uppercase; margin-bottom: 2rem; box-shadow: 0 0 10px rgba(57,255,20,0.2); }
.hero-dot { width: 8px; height: 8px; background: var(--accent3); box-shadow: 0 0 10px var(--accent3); animation: blink 1s step-end infinite; }
@keyframes blink { 50% { opacity: 0; } }
.hero-title { font-size: clamp(3rem, 7vw, 6rem); font-weight: 900; line-height: 1.1; margin-bottom: 1.5rem; text-shadow: 0 5px 15px rgba(0,0,0,0.8); }
.hero-title span { color: transparent; -webkit-text-stroke: 2px var(--accent); text-shadow: 0 0 20px var(--glow); }
.hero-desc { font-size: 1.25rem; font-weight: 500; line-height: 1.6; color: var(--text2); margin: 0 auto 3rem auto; max-width: 700px; }
.hero-actions { display: flex; gap: 1.5rem; flex-wrap: wrap; justify-content: center; }

/* ── GITHUB & YOUTUBE GRID ── */
.stats-yt-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 2rem; align-items: stretch; width: 100%; max-width: 1100px; margin-top: 4rem; z-index: 10; position: relative; }

.github-banner, .yt-banner {
  background: var(--card); backdrop-filter: blur(10px);
  border: 1px solid var(--border);
  clip-path: polygon(30px 0, 100% 0, 100% calc(100% - 30px), calc(100% - 30px) 100%, 0 100%, 0 30px);
  padding: 3.5rem 2rem; text-align: center; display: flex; flex-direction: column; align-items: center; justify-content: center; gap: 1.5rem;
  transition: all 0.4s; position: relative; overflow: hidden;
}
.github-banner::before, .yt-banner::before {
  content: ''; position: absolute; top: 0; left: 0; width: 100%; height: 4px; background: var(--accent); transition: height 0.3s;
}
.yt-banner::before { background: #ff0000; }
.github-banner:hover { transform: translateY(-10px); border-color: var(--accent); box-shadow: 0 15px 30px rgba(0,255,255,0.1); }
.github-banner:hover::before { height: 100%; opacity: 0.05; }
.yt-banner:hover { transform: translateY(-10px); border-color: #ff0000; box-shadow: 0 15px 30px rgba(255,0,0,0.1); }
.yt-banner:hover::before { height: 100%; opacity: 0.05; }

.github-icon, .yt-icon { width: 72px; height: 72px; fill: var(--text); filter: drop-shadow(0 0 10px rgba(255,255,255,0.2)); margin-bottom: -0.5rem; }
.yt-icon { fill: #ff0000; filter: drop-shadow(0 0 10px rgba(255,0,0,0.5)); }

.btn-github { display: inline-flex; align-items: center; gap: 8px; padding: 1rem 2rem; background: var(--text); color: var(--bg) !important; text-decoration: none; font-family: var(--font-heading); font-weight: 700; text-transform: uppercase; font-size: 1rem; clip-path: polygon(10px 0, 100% 0, 100% calc(100% - 10px), calc(100% - 10px) 100%, 0 100%, 0 10px); transition: all 0.3s; border: none; cursor: pointer; box-shadow: 0 0 15px rgba(255,255,255,0.2); }
.btn-github:hover { transform: scale(1.05); box-shadow: 0 0 25px rgba(255,255,255,0.4); background: #fff; }

.btn-youtube { display: inline-flex; align-items: center; gap: 8px; padding: 1rem 2rem; background: transparent; color: #ff0000 !important; border: 1px solid #ff0000; text-decoration: none; font-family: var(--font-heading); font-weight: 700; text-transform: uppercase; font-size: 1rem; clip-path: polygon(10px 0, 100% 0, 100% calc(100% - 10px), calc(100% - 10px) 100%, 0 100%, 0 10px); transition: all 0.3s; cursor: pointer; box-shadow: inset 0 0 10px rgba(255,0,0,0.2), 0 0 15px rgba(255,0,0,0.2); }
.btn-youtube:hover { transform: scale(1.05); background: #ff0000; color: #fff !important; box-shadow: 0 0 30px rgba(255,0,0,0.6); }

/* ── SECTIONS ── */
section.standard-section { padding: 5rem 2rem; max-width: 1200px; margin: 0 auto; width: 100%; position: relative; z-index: 10; }
.section-label { display: inline-flex; align-items: center; gap: 10px; font-family: var(--font-heading); font-size: 0.9rem; color: var(--accent2); font-weight: 700; letter-spacing: 2px; text-transform: uppercase; margin-bottom: 1rem; text-shadow: 0 0 8px var(--accent2); }
.section-label::before { content: '/>'; color: var(--accent); }
.section-title { font-size: clamp(2.2rem, 4vw, 3.5rem); font-weight: 900; letter-spacing: 1px; margin-bottom: 1rem; line-height: 1.1; text-shadow: 2px 2px 0px var(--accent); }
.section-desc { font-size: 1.15rem; font-weight: 500; color: var(--text2); max-width: 600px; line-height: 1.6; margin-bottom: 3rem; }
.divider { border: none; height: 1px; background: linear-gradient(90deg, transparent, var(--accent), transparent); max-width: 1100px; margin: 0 auto; width: calc(100% - 4rem); opacity: 0.5; }

/* ── HUD CARDS (Generic style for About, Projects, Blog, Skills) ── */
.hud-card {
  background: var(--card); backdrop-filter: blur(5px);
  border: 1px solid var(--border);
  clip-path: polygon(20px 0, 100% 0, 100% calc(100% - 20px), calc(100% - 20px) 100%, 0 100%, 0 20px);
  padding: 2rem; transition: all 0.3s; position: relative;
}
.hud-card:hover {
  border-color: var(--accent);
  box-shadow: 0 0 20px var(--glow);
  transform: translateY(-5px);
}

/* ── ABOUT ── */
.about-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 3rem; margin-top: 2rem; }
.about-text { color: var(--text); line-height: 1.8; font-size: 1.15rem; font-weight: 500; }
.about-text p + p { margin-top: 1.5rem; }
.about-highlights { display: flex; flex-direction: column; gap: 1.5rem; }

.highlight-item { background: rgba(0,255,255,0.05); border: 1px solid var(--border); clip-path: polygon(15px 0, 100% 0, 100% calc(100% - 15px), calc(100% - 15px) 100%, 0 100%, 0 15px); padding: 1.25rem 1.5rem; display: flex; align-items: center; gap: 1rem; transition: all 0.3s; }
.highlight-item:hover { background: rgba(0,255,255,0.1); border-color: var(--accent); box-shadow: inset 0 0 15px var(--glow); transform: translateX(10px); }
.highlight-icon { width: 45px; height: 45px; background: var(--accent); clip-path: polygon(50% 0%, 100% 25%, 100% 75%, 50% 100%, 0% 75%, 0% 25%); display: flex; align-items: center; justify-content: center; font-size: 1.5rem; flex-shrink: 0; color: #000; box-shadow: 0 0 10px var(--accent); }
.highlight-info strong { font-family: var(--font-heading); font-size: 1rem; font-weight: 700; display: block; margin-bottom: 4px; letter-spacing: 1px; color: var(--accent); }
.highlight-info span { font-size: 0.95rem; font-weight: 600; color: var(--text2); }

/* ── EXPERIENCE TIMELINE ── */
.timeline { display: flex; flex-direction: column; gap: 0; margin-top: 2rem; position: relative; }
.timeline::before { content: ''; position: absolute; left: 24px; top: 0; bottom: 0; width: 2px; background: var(--border); box-shadow: 0 0 5px var(--accent); }
.timeline-item { display: flex; gap: 2rem; padding: 0 0 3rem 0; position: relative; }
.timeline-dot { width: 50px; height: 50px; background: var(--bg); border: 2px solid var(--accent); clip-path: polygon(50% 0%, 100% 50%, 50% 100%, 0% 50%); display: flex; align-items: center; justify-content: center; font-size: 1.2rem; flex-shrink: 0; position: relative; z-index: 1; transition: all 0.3s; box-shadow: 0 0 15px var(--glow); }
.timeline-item:hover .timeline-dot { background: var(--accent); color: #000; transform: scale(1.2) rotate(90deg); }
.timeline-body { @extend .hud-card; flex: 1; padding: 1.5rem 2rem; }
.timeline-period { font-family: var(--font-heading); font-size: 0.85rem; font-weight: 700; color: var(--accent3); margin-bottom: 8px; letter-spacing: 1px; }
.timeline-role { font-family: var(--font-heading); font-size: 1.3rem; font-weight: 700; margin-bottom: 4px; color: var(--accent); text-transform: none; }
.timeline-org { font-size: 1rem; font-weight: 600; color: var(--text2); margin-bottom: 1rem; }
.timeline-points { list-style: none; display: flex; flex-direction: column; gap: 8px; }
.timeline-points li { font-size: 1.05rem; font-weight: 500; color: var(--text); line-height: 1.6; padding-left: 1.5rem; position: relative; }
.timeline-points li::before { content: '>'; font-family: var(--font-heading); font-weight: 900; position: absolute; left: 0; color: var(--accent2); top: 0; }

/* ── PROJECTS ── */
.projects-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(320px, 1fr)); gap: 2rem; margin-top: 2rem; }
.project-card { @extend .hud-card; padding: 2rem; }
.project-card::before { content: ''; position: absolute; top: 0; left: 0; right: 0; height: 3px; background: linear-gradient(90deg, var(--accent), var(--accent2)); transform: scaleX(0); transform-origin: left; transition: transform 0.4s; }
.project-card:hover::before { transform: scaleX(1); }
.project-date { font-family: var(--font-heading); font-size: 0.85rem; font-weight: 700; color: var(--accent3); margin-bottom: 1rem; letter-spacing: 1px; }
.project-icon { width: 50px; height: 50px; background: rgba(0,255,255,0.1); border: 1px solid var(--accent); clip-path: polygon(10px 0, 100% 0, 100% calc(100% - 10px), calc(100% - 10px) 100%, 0 100%, 0 10px); display: flex; align-items: center; justify-content: center; font-size: 1.5rem; margin-bottom: 1.2rem; box-shadow: inset 0 0 10px var(--glow); }
.project-name { font-family: var(--font-heading); font-size: 1.3rem; font-weight: 700; margin-bottom: 0.8rem; color: var(--text); }
.project-desc { font-size: 1.05rem; font-weight: 500; color: var(--text2); line-height: 1.6; }

/* ── BLOG GRID ── */
.blog-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(320px, 1fr)); gap: 2rem; margin-top: 2rem; }
.blog-card { @extend .hud-card; display: flex; flex-direction: column; padding: 2rem; border-top: 3px solid var(--accent2); }
.blog-date { font-family: var(--font-heading); font-size: 0.85rem; font-weight: 700; color: var(--accent); margin-bottom: 1rem; letter-spacing: 1px; }
.blog-title { font-family: var(--font-heading); font-size: 1.4rem; font-weight: 700; margin-bottom: 1rem; line-height: 1.3; text-transform: none; }
.blog-title a { color: var(--text); text-decoration: none; transition: color 0.3s; }
.blog-title a:hover { color: var(--accent); text-shadow: 0 0 10px var(--glow); }
.blog-snippet { font-size: 1.05rem; font-weight: 500; color: var(--text2); line-height: 1.6; margin-bottom: 1.5rem; flex-grow: 1; }
.read-more { display: inline-flex; align-items: center; gap: 8px; font-family: var(--font-heading); font-size: 0.95rem; font-weight: 700; color: var(--accent); text-decoration: none; text-transform: uppercase; align-self: flex-start; transition: all 0.3s; padding: 8px 16px; border: 1px solid var(--accent); clip-path: polygon(8px 0, 100% 0, 100% calc(100% - 8px), calc(100% - 8px) 100%, 0 100%, 0 8px); background: rgba(0,255,255,0.05); }
.read-more:hover { background: var(--accent); color: #000; box-shadow: 0 0 15px var(--accent); padding-left: 20px; }

/* ── FULL POST VIEW ── */
.post-container {
  background: var(--card); backdrop-filter: blur(10px);
  border: 1px solid var(--border); clip-path: polygon(40px 0, 100% 0, 100% calc(100% - 40px), calc(100% - 40px) 100%, 0 100%, 0 40px);
  padding: 4rem; width: 95%; max-width: 1000px;
  margin: 2rem auto 4rem; box-shadow: 0 0 30px rgba(0,0,0,0.8), inset 0 0 20px rgba(0,255,255,0.05);
}
@media (max-width: 768px) { .post-container { padding: 2.5rem 1.5rem; clip-path: polygon(20px 0, 100% 0, 100% calc(100% - 20px), calc(100% - 20px) 100%, 0 100%, 0 20px); } }

.post-header { text-align: center; margin-bottom: 3.5rem; border-bottom: 1px dashed var(--border); padding-bottom: 3rem; position: relative; }
.post-header h1 {
  font-size: clamp(2.2rem, 5vw, 4rem); margin: 1rem 0; line-height: 1.1; font-weight: 900;
  color: var(--text); text-shadow: 3px 3px 0 var(--accent2), -2px -2px 0 var(--accent);
}
.post-meta-tags {
  display: flex; flex-wrap: wrap; justify-content: center; align-items: center; gap: 1rem;
  font-family: var(--font-heading); font-size: 0.9rem; font-weight: 700; margin-top: 1.5rem; letter-spacing: 1px;
}
.post-tag { background: rgba(0,255,255,0.1); border: 1px solid var(--accent); padding: 4px 14px; clip-path: polygon(5px 0, 100% 0, 100% calc(100% - 5px), calc(100% - 5px) 100%, 0 100%, 0 5px); color: var(--accent); text-transform: uppercase; }

.post-hero-image {
  width: 100%; aspect-ratio: 16 / 9; overflow: hidden;
  clip-path: polygon(20px 0, 100% 0, 100% calc(100% - 20px), calc(100% - 20px) 100%, 0 100%, 0 20px);
  border: 2px solid var(--border); box-shadow: 0 0 20px var(--glow); margin: 0 auto 3.5rem auto;
}
.post-hero-image img { width: 100% !important; height: 100% !important; object-fit: cover !important; transition: transform 0.5s ease; }
.post-hero-image:hover img { transform: scale(1.05); }

.post-body .separator, .post-body img { display: none !important; }

.post-body { font-size: 1.25rem; line-height: 1.8; color: var(--text); max-width: 800px; margin: 0 auto; font-weight: 500; }
.post-body h2, .post-body h3, .post-body h4 { font-family: var(--font-heading); color: var(--accent); margin: 3rem 0 1.5rem; font-weight: 700; line-height: 1.3; text-shadow: 0 0 10px rgba(0,255,255,0.3); }
.post-body p { margin-bottom: 1.5rem; color: #ccc; }
.post-body a { color: var(--accent3); text-decoration: none; border-bottom: 2px solid var(--accent3); font-weight: 600; transition: all 0.2s; }
.post-body a:hover { color: #000; background: var(--accent3); box-shadow: 0 0 10px var(--accent3); }

.post-body blockquote {
  border-left: 4px solid var(--accent2);
  background: linear-gradient(90deg, rgba(255,0,255,0.1), transparent);
  padding: 1.5rem 2rem; margin: 2.5rem 0; font-style: italic; color: var(--text);
  clip-path: polygon(0 0, 100% 0, 100% 100%, 20px 100%, 0 calc(100% - 20px));
}

.post-body pre {
  background: #000; border: 1px solid var(--border);
  clip-path: polygon(10px 0, 100% 0, 100% calc(100% - 10px), calc(100% - 10px) 100%, 0 100%, 0 10px);
  padding: 1.5rem; overflow-x: auto; margin: 2.5rem 0; box-shadow: inset 0 0 15px rgba(0,255,255,0.1);
}
.post-body code { font-family: 'Courier New', monospace; font-size: 1rem; color: var(--accent3); }

/* ── SKILLS ── */
.skills-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(280px, 1fr)); gap: 1.5rem; margin-top: 2rem; }
.skill-category { @extend .hud-card; padding: 2rem; }
.skill-cat-title { font-family: var(--font-heading); font-size: 1rem; font-weight: 700; text-transform: uppercase; letter-spacing: 2px; color: var(--accent); margin-bottom: 1.5rem; display: flex; align-items: center; gap: 12px; }
.skill-cat-title::after { content: ''; flex: 1; height: 1px; background: linear-gradient(90deg, var(--accent), transparent); }
.skill-tags { display: flex; flex-wrap: wrap; gap: 10px; }
.skill-tag { padding: 6px 14px; background: rgba(0,0,0,0.5); border: 1px solid var(--border); clip-path: polygon(8px 0, 100% 0, 100% calc(100% - 8px), calc(100% - 8px) 100%, 0 100%, 0 8px); font-family: var(--font-heading); font-size: 0.85rem; font-weight: 700; color: var(--text); letter-spacing: 1px; transition: all 0.3s; cursor: default; }
.skill-tag:hover { background: var(--accent); color: #000; border-color: var(--accent); box-shadow: 0 0 15px var(--accent); transform: scale(1.05); }

.certs-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(220px, 1fr)); gap: 1.5rem; margin-top: 2rem; }
.cert-card { @extend .hud-card; padding: 1.5rem; border-top: 2px solid var(--accent3); }
.cert-issuer { font-family: var(--font-heading); font-size: 0.85rem; font-weight: 700; color: var(--accent3); text-transform: uppercase; letter-spacing: 1px; margin-bottom: 8px; }
.cert-name { font-size: 1.1rem; font-weight: 700; margin-bottom: 6px; color: var(--text); }
.cert-date { font-family: var(--font-heading); font-size: 0.8rem; font-weight: 700; color: var(--text2); }

/* ── CONTACT ── */
.contact-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 3rem; margin-top: 2rem; }
.contact-info { display: flex; flex-direction: column; gap: 1.5rem; }
.contact-item { background: rgba(0,0,0,0.4); border: 1px solid var(--border); clip-path: polygon(15px 0, 100% 0, 100% calc(100% - 15px), calc(100% - 15px) 100%, 0 100%, 0 15px); padding: 1.25rem 1.5rem; display: flex; align-items: center; gap: 1.25rem; text-decoration: none; color: var(--text); transition: all 0.3s; }
.contact-item:hover { border-color: var(--accent2); background: rgba(255,0,255,0.05); transform: translateX(10px); box-shadow: inset 0 0 15px rgba(255,0,255,0.2); }
.contact-icon { width: 45px; height: 45px; background: var(--accent2); clip-path: polygon(50% 0%, 100% 25%, 100% 75%, 50% 100%, 0% 75%, 0% 25%); display: flex; align-items: center; justify-content: center; font-size: 1.2rem; flex-shrink: 0; color: #000; box-shadow: 0 0 10px var(--accent2); }
.contact-label { font-family: var(--font-heading); font-size: 0.85rem; font-weight: 700; color: var(--accent2); margin-bottom: 4px; letter-spacing: 1px; text-transform: uppercase; }
.contact-value { font-size: 1.1rem; font-weight: 600; }

.contact-card { background: linear-gradient(135deg, rgba(0,255,255,0.1), rgba(255,0,255,0.05)); border: 1px solid var(--accent); clip-path: polygon(30px 0, 100% 0, 100% calc(100% - 30px), calc(100% - 30px) 100%, 0 100%, 0 30px); padding: 3rem; display: flex; flex-direction: column; justify-content: center; gap: 1.5rem; transition: all 0.4s; box-shadow: inset 0 0 20px rgba(0,255,255,0.1); }
.contact-card:hover { border-color: var(--accent2); box-shadow: inset 0 0 30px rgba(255,0,255,0.2), 0 0 20px rgba(255,0,255,0.2); }
.contact-card h3 { font-family: var(--font-heading); font-size: 1.8rem; font-weight: 900; text-transform: none; text-shadow: 2px 2px 0 var(--accent); }
.contact-card p { font-size: 1.15rem; font-weight: 500; color: var(--text2); line-height: 1.6; }

/* ── ADS / SPONSOR BLOCKS ── */
.ad-sponsor-block {
  margin: 2rem auto; text-align: center; min-height: 100px; 
  background: rgba(0,0,0,0.6); border: 1px solid var(--border);
  clip-path: polygon(15px 0, 100% 0, 100% calc(100% - 15px), calc(100% - 15px) 100%, 0 100%, 0 15px);
  display: flex; flex-direction: column; align-items: center; justify-content: center;
  position: relative; padding: 1rem;
}
.ad-sponsor-label {
  position: absolute; top: -1px; left: 20px; background: var(--accent); color: #000;
  font-family: var(--font-heading); font-size: 0.7rem; font-weight: 900; padding: 2px 10px;
  letter-spacing: 2px; text-transform: uppercase; clip-path: polygon(0 0, 100% 0, 90% 100%, 0% 100%);
}

/* ── FOOTER ── */
.site-footer { border-top: 2px solid var(--accent); background: rgba(5,5,8,0.9); padding: 2rem; margin-top: 5rem; position: relative; z-index: 10; text-align: center; box-shadow: 0 -10px 30px rgba(0,255,255,0.1); }
.footer-bottom { max-width: 1200px; margin: 0 auto; display: flex; justify-content: space-between; align-items: center; flex-wrap: wrap; gap: 1.5rem; }
.footer-bottom p { font-size: 1rem; font-weight: 600; color: var(--text2); margin: 0; }
.footer-credit { font-family: var(--font-heading); color: var(--accent); font-weight: 700; letter-spacing: 1px; }
.footer-heart { color: var(--accent2); text-shadow: 0 0 10px var(--accent2); margin: 0 4px; }
.footer-inline-links .widget { margin: 0; }
.inline-legal-links { display: flex; gap: 2rem; justify-content: center; align-items: center; flex-wrap: wrap; }
.inline-legal-links a { font-family: var(--font-heading); color: var(--text2); text-decoration: none; font-size: 0.9rem; font-weight: 700; text-transform: uppercase; letter-spacing: 1px; transition: all 0.3s; }
.inline-legal-links a:hover { color: var(--accent); text-shadow: 0 0 8px var(--accent); }

/* ── RESPONSIVE MOBILE VIEW ── */
@media (max-width: 768px) {
  .hero { padding: 6rem 2rem 3rem; }
  .stats-yt-grid { grid-template-columns: 1fr; }
  .about-grid, .contact-grid { grid-template-columns: 1fr; }

  .hamburger { display: block; }
  .nav-right {
    display: none; position: absolute; top: 100%; left: 0; width: 100%;
    background: rgba(10,10,15,0.95); backdrop-filter: blur(10px); border-bottom: 2px solid var(--accent);
    flex-direction: column; padding: 2rem; gap: 2rem; z-index: 100; box-shadow: 0px 10px 30px rgba(0,0,0,0.8);
  }
  .nav-right.active { display: flex; }
  .nav-links { flex-direction: column; width: 100%; gap: 1.5rem; }

  .search-form { margin: 0; width: 100%; order: -1; margin-bottom: 1rem; }
  .search-input { width: 100%; }
  .search-input:focus { width: 100%; }

  .dropdown-content { position: static; box-shadow: none; border: none; border-left: 2px solid var(--accent); border-top: none; padding-left: 1rem; margin-top: 1rem; background: transparent; display: none; }
  .dropdown:hover .dropdown-content { display: block; }
  .footer-bottom { flex-direction: column; text-align: center; justify-content: center; gap: 1rem; }
}

/* ── SCROLLBAR ── */
::-webkit-scrollbar { width: 8px; }
::-webkit-scrollbar-track { background: var(--bg); border-left: 1px solid var(--border); }
::-webkit-scrollbar-thumb { background: var(--accent); border-radius: 0; }
::-webkit-scrollbar-thumb:hover { background: var(--accent2); }

body.script:
//
  // ── THEME TOGGLE ──
  function toggleTheme() {
    const body = document.body;
    const current = body.getAttribute('data-theme');
    body.setAttribute('data-theme', current === 'light' ? '' : 'light');
    localStorage.setItem('theme', body.getAttribute('data-theme'));
  }
  (function() {
    const saved = localStorage.getItem('theme');
    if (saved === 'light') document.body.setAttribute('data-theme', 'light');
  })();

  // ── MOBILE MENU TOGGLE ──
  function toggleMenu() {
    const navMenu = document.getElementById('nav-menu');
    navMenu.classList.toggle('active');
  }

  // ── SCROLL REVEAL ──
  const observer = new IntersectionObserver((entries) => {
    entries.forEach(e => {
      if (e.isIntersecting) {
        e.target.classList.add('visible');
        observer.unobserve(e.target);
      }
    });
  }, { threshold: 0.1, rootMargin: '0px 0px -40px 0px' });

  const revealElements = document.querySelectorAll('.reveal');
  if(revealElements.length > 0) {
      revealElements.forEach(el => observer.observe(el));
  }

  // ── READING PROGRESS BAR ──
  window.addEventListener('scroll', () => {
    const winScroll = document.body.scrollTop || document.documentElement.scrollTop;
    const height = document.documentElement.scrollHeight - document.documentElement.clientHeight;
    const scrolled = (winScroll / height) * 100;
    const progressBar = document.getElementById('reading-progress');
    if (progressBar) progressBar.style.width = scrolled + '%';
  });

  // ── HIDE OVERLAY CLEANUP ──
  setTimeout(() => {
    const overlay = document.getElementById('intro-overlay');
    if (overlay) overlay.style.display = 'none';
  }, 2500);

  // ── CLEANUP LEFTOVER SPACES FROM HIDDEN IMAGES ──
  document.addEventListener("DOMContentLoaded", function() {
    if (document.querySelector('.post-container')) {
      const postBodies = document.querySelectorAll('.post-body');
      postBodies.forEach(body => {
        let node = body.firstChild;
        while (node) {
          let next = node.nextSibling;
          if (node.nodeName === 'BR' || 
             (node.nodeType === 3 && node.textContent.trim() === '') ||
             (node.classList && node.classList.contains('separator')) ||
             (node.nodeName === 'P' && node.innerHTML.trim() === '')) {
            node.remove();
          } else {
            break;
          }
          node = next;
        }
      });
    }
  });
//
